const allItems = $input.all();
const emailData = [];

allItems.forEach((row, index) => {
  const email = row.json?.Email?.trim?.();
  if (!email) return;

  const status = row.json?.Status?.trim?.();

  if (status && status !== 'empty') {
    return;
  }

  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  if (!emailRegex.test(email)) return;

  emailData.push({
    email: email.toLowerCase(),
    row: row.json?.row_number || 0
  });
});

if (emailData.length === 0) {
  return [];
}

const BATCH_SIZE = 100;
const batches = [];

for (let i = 0; i < emailData.length; i += BATCH_SIZE) {
  const batch = emailData.slice(i, i + BATCH_SIZE);
  batches.push({
    emails: batch.map(e => e.email),
    emailData: batch
  });
}

return batches.map(batch => ({ json: batch }));

let apiResults = [];

try {
  const response = $input.item.json;
  apiResults = Array.isArray(response) ? response : response?.results || [];

  if (!Array.isArray(apiResults) || apiResults.length === 0) {
    throw new Error('API returned empty response');
  }
} catch (e) {
  throw new Error('API Error: ' + e.message);
}

const currentBatch = $('Parse Email Data for Batches').item.json;
const emailData = currentBatch.emailData || [];
const emailToRow = {};

emailData.forEach(e => {
  emailToRow[e.email] = e;
});

const results = apiResults.map(result => {
  const originalData = emailToRow[result.email_address] || {};
  const shouldBlock = result.block === true || result.valid === false;

  const reasons = [];
  if (result.valid === false) reasons.push('Invalid');
  if (result.block === true) reasons.push('Blacklisted');
  if (result.disposable === true) reasons.push('Disposable');

  return {
    Email: result.email_address,
    Status: shouldBlock ? 'Block' : 'Valid',
    Reason: reasons.join(' + ') || '-'
  };
});

return results.map(r => ({ json: r }));
